export enum Category {
  SHORT_STORY = 'Short Story',
  SCRIPT = 'Script',
  NOVEL = 'Novel',
  POEM = 'Poem',
  THOUGHT = 'Random Thought',
}

export interface Work {
  id: string;
  title: string;
  category: Category;
  description: string;
  coverImage?: string; // Data URL
  pdfContent?: string; // Data URL for the PDF
  dateCreated: number;
  isLocked: boolean; // If true, requires login to download/view full
}

export interface User {
  username: string;
  role: 'admin' | 'user' | 'guest';
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

import { Work, Category, User } from '../types';

const WORKS_KEY = 'writer_portfolio_works';
const USER_KEY = 'writer_portfolio_user';

// Initial Mock Data
const INITIAL_WORKS: Work[] = [
  {
    id: '1',
    title: 'The Silent Clocktower',
    category: Category.SHORT_STORY,
    description: 'A mystery set in a town where time stopped moving forward in 1999.',
    dateCreated: Date.now() - 10000000,
    isLocked: false,
    coverImage: 'https://picsum.photos/400/600?grayscale',
  },
  {
    id: '2',
    title: 'Echoes of rain',
    category: Category.POEM,
    description: 'A collection of haikus about urban melancholy.',
    dateCreated: Date.now() - 5000000,
    isLocked: true,
    coverImage: 'https://picsum.photos/400/600?blur=2',
  },
  {
    id: '3',
    title: 'Project: Red Dust',
    category: Category.SCRIPT,
    description: 'Screenplay for a sci-fi short film about terraforming gone wrong.',
    dateCreated: Date.now(),
    isLocked: true,
    coverImage: 'https://picsum.photos/400/600',
  },
];

export const getWorks = (): Work[] => {
  const stored = localStorage.getItem(WORKS_KEY);
  if (!stored) {
    localStorage.setItem(WORKS_KEY, JSON.stringify(INITIAL_WORKS));
    return INITIAL_WORKS;
  }
  return JSON.parse(stored);
};

export const saveWork = (work: Work): void => {
  const works = getWorks();
  // Check if update or new
  const index = works.findIndex(w => w.id === work.id);
  if (index >= 0) {
    works[index] = work;
  } else {
    works.unshift(work);
  }
  localStorage.setItem(WORKS_KEY, JSON.stringify(works));
};

export const deleteWork = (id: string): void => {
  const works = getWorks();
  const filtered = works.filter(w => w.id !== id);
  localStorage.setItem(WORKS_KEY, JSON.stringify(filtered));
};

export const getCurrentUser = (): User => {
  const stored = localStorage.getItem(USER_KEY);
  if (stored) return JSON.parse(stored);
  return { username: 'Guest', role: 'guest' };
};

export const loginUser = (username: string, isAdmin: boolean): User => {
  const user: User = {
    username,
    role: isAdmin ? 'admin' : 'user',
  };
  localStorage.setItem(USER_KEY, JSON.stringify(user));
  return user;
};

export const logoutUser = (): void => {
  localStorage.removeItem(USER_KEY);
};

import { GoogleGenAI } from "@google/genai";
import { Work } from "../types";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API Key not found in environment variables");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const generateWorkSummary = async (title: string, category: string, contentSnippet: string): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "AI services unavailable (Missing API Key).";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an editor for a creative writer. Please write a compelling, one-sentence tagline or short summary (max 30 words) for a ${category} titled "${title}". Here is a snippet of the content/idea: "${contentSnippet}". Make it intriguing.`,
    });
    return response.text || "Could not generate summary.";
  } catch (error) {
    console.error("Gemini Summary Error:", error);
    return "Error generating summary.";
  }
};

export const chatWithPortfolio = async (
  history: { role: 'user' | 'model', text: string }[],
  works: Work[],
  newMessage: string
): Promise<string> => {
  const ai = getAIClient();
  if (!ai) return "I can't access my brain right now (Missing API Key).";

  // Construct a context string based on available works
  const portfolioContext = works.map(w =>
    `- Title: ${w.title} (${w.category})
     - Description: ${w.description}
     - Created: ${new Date(w.dateCreated).toLocaleDateString()}
     - Status: ${w.isLocked ? "Requires Login" : "Public"}
    `
  ).join('\n');

  const systemInstruction = `You are the "Digital Assistant" for a writer's portfolio website.
  Your goal is to engage visitors, answer questions about the author's work based on the list below, and encourage them to read.

  The Author's Portfolio contains these works:
  ${portfolioContext}

  If a user asks about a specific story, provide details from the description.
  If they ask for a recommendation, pick one based on their mood (infer from their text).
  Keep your tone creative, slightly mysterious, but helpful.
  Do not make up facts about the stories that aren't in the descriptions, but you can be playfully vague if you don't know.
  `;

  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessage({ message: newMessage });
    return result.text || "I'm lost for words.";
  } catch (error) {
    console.error("Gemini Chat Error:", error);
    return "Something went wrong in the ether.";
  }
};

import React, { useState, useRef } from 'react';
import { Category, Work } from '../types';
import { generateWorkSummary } from '../services/geminiService';
import { saveWork, deleteWork } from '../services/storageService';

interface AdminPanelProps {
  works: Work[];
  onUpdate: () => void;
  onClose: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ works, onUpdate, onClose }) => {
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<Category>(Category.SHORT_STORY);
  const [description, setDescription] = useState('');
  const [isLocked, setIsLocked] = useState(true);
  const [coverImage, setCoverImage] = useState<string | undefined>(undefined);
  const [pdfContent, setPdfContent] = useState<string | undefined>(undefined);

  const [isGenerating, setIsGenerating] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const pdfInputRef = useRef<HTMLInputElement>(null);

  const handleFileRead = (file: File, callback: (result: string) => void) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      if (typeof reader.result === 'string') callback(reader.result);
    };
    reader.readAsDataURL(file);
  };

  const handleCoverUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      handleFileRead(e.target.files[0], setCoverImage);
    }
  };

  const handlePdfUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      handleFileRead(e.target.files[0], setPdfContent);
    }
  };

  const handleAISummary = async () => {
    if (!title) return;
    setIsGenerating(true);
    const summary = await generateWorkSummary(title, category, description || "A story about...");
    setDescription(summary);
    setIsGenerating(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newWork: Work = {
      id: Date.now().toString(),
      title,
      category,
      description,
      isLocked,
      dateCreated: Date.now(),
      coverImage: coverImage || `https://picsum.photos/400/600?random=${Date.now()}`,
      pdfContent,
    };
    saveWork(newWork);
    onUpdate();
    resetForm();
  };

  const resetForm = () => {
    setTitle('');
    setDescription('');
    setCoverImage(undefined);
    setPdfContent(undefined);
    if(fileInputRef.current) fileInputRef.current.value = '';
    if(pdfInputRef.current) pdfInputRef.current.value = '';
  };

  const handleDelete = (id: string) => {
    if(window.confirm("Are you sure you want to delete this work?")) {
      deleteWork(id);
      onUpdate();
    }
  }

  return (
    <div className="fixed inset-0 bg-ink/50 backdrop-blur-sm z-50 flex justify-end">
      <div className="w-full max-w-xl bg-white h-full shadow-2xl p-8 overflow-y-auto animate-slide-in-right">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-3xl font-serif text-ink">Manage Portfolio</h2>
          <button onClick={onClose} className="text-gray-500 hover:text-ink">
            <i className="fa-solid fa-times text-2xl"></i>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6 mb-12 border-b border-gray-200 pb-12">
          <h3 className="text-xl font-bold text-gray-800">Add New Work</h3>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
            <input 
              required
              type="text" 
              value={title} 
              onChange={e => setTitle(e.target.value)}
              className="w-full border-gray-300 border rounded-md p-2 focus:ring-accent focus:border-accent"
              placeholder="Enter title..."
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
              <select 
                value={category} 
                onChange={e => setCategory(e.target.value as Category)}
                className="w-full border-gray-300 border rounded-md p-2"
              >
                {Object.values(Category).map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
            <div className="flex items-center pt-6">
               <label className="flex items-center space-x-2 cursor-pointer">
                 <input 
                    type="checkbox" 
                    checked={isLocked}
                    onChange={e => setIsLocked(e.target.checked)}
                    className="rounded text-accent focus:ring-accent"
                 />
                 <span className="text-sm text-gray-700">Require Login to View</span>
               </label>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-1">
              <label className="block text-sm font-medium text-gray-700">Description</label>
              <button 
                type="button"
                onClick={handleAISummary}
                disabled={isGenerating || !title}
                className={`text-xs flex items-center gap-1 ${isGenerating ? 'text-gray-400' : 'text-accent hover:text-orange-700'}`}
              >
                <i className={`fa-solid fa-wand-magic-sparkles ${isGenerating ? 'animate-pulse' : ''}`}></i>
                {isGenerating ? 'Generating...' : 'AI Generate'}
              </button>
            </div>
            <textarea 
              value={description} 
              onChange={e => setDescription(e.target.value)}
              className="w-full border-gray-300 border rounded-md p-2 h-24"
              placeholder="Short description or synopsis..."
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Cover Art</label>
              <input 
                ref={fileInputRef}
                type="file" 
                accept="image/*"
                onChange={handleCoverUpload}
                className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-orange-50 file:text-accent hover:file:bg-orange-100"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">PDF File</label>
              <input 
                ref={pdfInputRef}
                type="file" 
                accept="application/pdf"
                onChange={handlePdfUpload}
                className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-gray-100 file:text-gray-700 hover:file:bg-gray-200"
              />
            </div>
          </div>

          <button 
            type="submit" 
            className="w-full bg-ink text-white py-3 rounded-md hover:bg-gray-800 transition-colors font-semibold"
          >
            Publish Work
          </button>
        </form>

        <div className="space-y-4">
          <h3 className="text-xl font-bold text-gray-800">Existing Works</h3>
          {works.map(work => (
            <div key={work.id} className="flex items-center justify-between bg-gray-50 p-4 rounded-lg border border-gray-100">
              <div className="flex items-center space-x-4">
                <img src={work.coverImage} alt={work.title} className="w-12 h-16 object-cover rounded shadow-sm" />
                <div>
                  <h4 className="font-serif font-bold text-ink">{work.title}</h4>
                  <p className="text-xs text-gray-500">{work.category}</p>
                </div>
              </div>
              <button 
                onClick={() => handleDelete(work.id)}
                className="text-red-400 hover:text-red-600 p-2"
              >
                <i className="fa-solid fa-trash"></i>
              </button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;

