    views: 5,
    downloads: 0,
  },
];

export const getWorks = (): Work[] => {
  const stored = localStorage.getItem(WORKS_KEY);
  if (!stored) {
    localStorage.setItem(WORKS_KEY, JSON.stringify(INITIAL_WORKS));
    return INITIAL_WORKS;
  }
  return JSON.parse(stored);
};

export const saveWork = (work: Work): void => {
  const works = getWorks();
  // Check if update or new
  const index = works.findIndex(w => w.id === work.id);
  if (index >= 0) {
    works[index] = work;
  } else {
    works.unshift(work);
  }
  localStorage.setItem(WORKS_KEY, JSON.stringify(works));
};

export const deleteWork = (id: string): void => {
  const works = getWorks();
  const filtered = works.filter(w => w.id !== id);
  localStorage.setItem(WORKS_KEY, JSON.stringify(filtered));
};

export const incrementWorkView = (id: string): Work[] => {
  const works = getWorks();
  const index = works.findIndex(w => w.id === id);
  if (index >= 0) {
    works[index].views = (works[index].views || 0) + 1;
    localStorage.setItem(WORKS_KEY, JSON.stringify(works));
  }
  return works;
};

export const incrementWorkDownload = (id: string): Work[] => {
  const works = getWorks();
  const index = works.findIndex(w => w.id === id);
  if (index >= 0) {
    works[index].downloads = (works[index].downloads || 0) + 1;
    localStorage.setItem(WORKS_KEY, JSON.stringify(works));
  }
  return works;
};

export const getCurrentUser = (): User => {
  const stored = localStorage.getItem(USER_KEY);
  if (stored) return JSON.parse(stored);
  return { username: 'Guest', role: 'guest' };
};

export const loginUser = (username: string, isAdmin: boolean): User => {
  const user: User = {
    username,
    role: isAdmin ? 'admin' : 'user',
  };
  localStorage.setItem(USER_KEY, JSON.stringify(user));
  return user;
};

export const logoutUser = (): void => {
  localStorage.removeItem(USER_KEY);
};

