import React, { useState, useEffect } from 'react';
import { Work, Category, User } from './types';
import { getWorks, getCurrentUser, loginUser, logoutUser, incrementWorkView, incrementWorkDownload } from './services/storageService';
import WorkCard from './components/WorkCard';
import AdminPanel from './components/AdminPanel';
import ChatBot from './components/ChatBot';
import ContactModal from './components/ContactModal';

const App: React.FC = () => {
  const [works, setWorks] = useState<Work[]>([]);
  const [user, setUser] = useState<User>(getCurrentUser());
  const [filter, setFilter] = useState<Category | 'All'>('All');
  const [showAdmin, setShowAdmin] = useState(false);
  const [showContact, setShowContact] = useState(false);
  const [selectedWork, setSelectedWork] = useState<Work | null>(null);
  const [showLogin, setShowLogin] = useState(false);

  // Login State Management
  const [loginMode, setLoginMode] = useState<'member' | 'verification-sent' | 'admin'>('member');
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  // Simulated Email Notification
  const [showFakeEmailNotification, setShowFakeEmailNotification] = useState(false);

  useEffect(() => {
    setWorks(getWorks());
  }, []);

  const handleUpdateWorks = () => {
    setWorks(getWorks());
  };

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.toLowerCase() === 'admin' && password === 'admin') {
      setUser(loginUser('Admin', true));
      closeLoginModal();
    } else {
      alert('Invalid admin credentials.');
    }
  };

  const handleMemberEmailSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!email.includes('@')) {
      alert('Please enter a valid email address.');
      return;
    }
    setLoginMode('verification-sent');

    // Simulate network delay and email arrival
    setTimeout(() => {
      setShowFakeEmailNotification(true);
    }, 1500);
  };

  const handleVerifyEmailLink = () => {
    setUser(loginUser(email, false));
    setShowFakeEmailNotification(false);
    setShowLogin(false);

    // Reset state for next time
    setTimeout(() => {
      setLoginMode('member');
      setEmail('');
      setUsername('');
      setPassword('');
    }, 500);
  };

  const handleLogout = () => {
    logoutUser();
    setUser({ username: 'Guest', role: 'guest' });
    setShowAdmin(false);
  };

  const closeLoginModal = () => {
    setShowLogin(false);
    // Reset to default state after transition
    setTimeout(() => {
      if (loginMode !== 'verification-sent') {
        setLoginMode('member');
        setUsername('');
        setPassword('');
      }
    }, 300);
  };

  const filteredWorks = filter === 'All' 
    ? works 
    : works.filter(w => w.category === filter);

  const canAccessWork = (work: Work) => {
    if (!work.isLocked) return true;
    return user.role !== 'guest';
  };

  const handleViewWork = (work: Work) => {
    // Increment view count when opening details
    const updatedWorks = incrementWorkView(work.id);
    setWorks(updatedWorks);

    // Find the updated work to display
    const updatedWork = updatedWorks.find(w => w.id === work.id);
    setSelectedWork(updatedWork || work);
  };

  const handleDownload = (work: Work) => {
    if (!work.pdfContent) {
      alert("No PDF file attached to this work.");
      return;
    }

    // Increment download count
    const updatedWorks = incrementWorkDownload(work.id);
    setWorks(updatedWorks);

    // Update selected work reference to reflect new stats if needed
    if (selectedWork && selectedWork.id === work.id) {
       const updated = updatedWorks.find(w => w.id === work.id);
       if (updated) setSelectedWork(updated);
    }

    const link = document.createElement('a');
    link.href = work.pdfContent;
    link.download = `${work.title.replace(/\s+/g, '_')}.pdf`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
