              {Object.values(Category).map(c => (
                <button 
                  key={c} 
                  onClick={() => setFilter(c)}
                  className={`px-3 py-1 rounded-full transition-colors ${filter === c ? 'bg-ink text-white' : 'hover:bg-gray-200'}`}
                >
                  {c}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-4 border-l border-gray-300 pl-6">
