                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        className="w-full border border-gray-300 rounded p-2 focus:border-accent focus:ring-1 focus:ring-accent outline-none" 
                      />
                   </div>
                   <button type="submit" className="w-full bg-ink text-white py-2 rounded font-semibold hover:bg-gray-800 transition-colors">
                     Enter
                   </button>
                 </form>
                 <div className="mt-6 pt-6 border-t border-gray-100 text-center">
                    <button onClick={() => setLoginMode('member')} className="text-xs text-gray-400 hover:text-ink">
                      Back to Member Access
                    </button>
                 </div>
               </>
             )}
          </div>
        </div>
      )}

      {/* Simulated Notification Toast */}
      {showFakeEmailNotification && (
        <div 
          onClick={handleVerifyEmailLink}
          className="fixed top-4 right-4 bg-white border-l-4 border-accent shadow-xl p-4 rounded cursor-pointer animate-bounce z-[60] max-w-xs hover:bg-gray-50 transition-colors"
          title="Click to simulate verifying email"
        >
           <div className="flex items-start gap-3">
              <div className="bg-accent/10 p-2 rounded-full text-accent">
                 <i className="fa-solid fa-envelope"></i>
              </div>
              <div>
                 <h4 className="font-bold text-sm text-gray-900">Login Link</h4>
                 <p className="text-xs text-gray-500 mt-1">
                   Login to Thomas Yazar Portfolio<br/>
                   <span className="text-accent font-semibold">Click to Verify</span>
                 </p>
              </div>
           </div>
        </div>
      )}

      <ChatBot works={works} />

    </div>
  );
};

export default App;
